function decode(str) {
if(String(str).search(/JP2\/W5V/)>=0){
Data=String(str).substring(3,String(str).length-4);
str=java.aesBase64DecodeToString(Data,"6CB1E21E","DES/CBC/PKCS5Padding","1F0FB845");}
else str=str;
